"""rAIdio.bot — Python interpreter customizations for the embedded ComfyUI.

Auto-loaded by site.py at every interpreter startup in python_embeded/.
That includes:
  1. ComfyUI main process (python.exe -s ComfyUI/main.py …) — sitecustomize
     (NOT usercustomize) loads under -s.
  2. RVC's training Popen subprocess (python.exe train.py …)
  3. The mp.Process children that subprocess spawns. Windows uses 'spawn' →
     each child is a fresh interpreter that re-runs site.py and re-loads us.

Layer 3 is what we care about: ComfyUI-RVC's
rvc/infer/modules/train/train.py:129 calls
  torch.distributed.init_process_group(backend="gloo",
      init_method="env://", world_size=n_gpus, rank=rank)
unconditionally, even when n_gpus == 1 and there is exactly one rank with
nothing to coordinate. On Windows the gloo backend's hostname resolution
dies with "makeDeviceForHostname(): unsupported gloo device" and the
trainer subprocess crashes before producing any .pth.

We single-GPU-only ship; rank coordination is never needed. This patch
turns init_process_group into a no-op for world_size <= 1 and leaves
multi-rank calls alone. We do NOT eagerly import torch at sitecustomize
time — that would break ComfyUI's argparse pipeline (see incident
2026-04-30 A5/A2 in supporting_materials/BROKEN_NOTES.md). Instead we
register a sys.meta_path finder that wraps torch.distributed's loader
and patches the module after the real import finishes.

Licensed under GPL-3.0 to match the GPL-3.0 PyTorch ecosystem.
Source: https://github.com/rAIdio-bot/rAIdio-nodes (mirror)
"""

import logging
import os
import sys

_TARGET = "torch.distributed"
_PATCHED = False


def _patch_init_process_group(dist_module):
    global _PATCHED
    if _PATCHED:
        return
    real_init = getattr(dist_module, "init_process_group", None)
    if real_init is None or getattr(real_init, "_raidio_dist_patched", False):
        return

    def _patched(
        backend=None,
        init_method=None,
        timeout=None,
        world_size=None,
        rank=None,
        store=None,
        group_name="",
        pg_options=None,
        device_id=None,
    ):
        ws = world_size
        if ws is None:
            try:
                ws = int(os.environ.get("WORLD_SIZE", "1"))
            except (TypeError, ValueError):
                ws = 1
        try:
            ws_int = int(ws)
        except (TypeError, ValueError):
            ws_int = 2  # unknown → fall through to real call

        if ws_int <= 1:
            msg = (
                "[rAIdio dist-noop] init_process_group intercepted "
                "(world_size={}); skipping. gloo on Windows can't construct "
                "a Device for single-rank — neither hostname nor interface "
                "lookup works. DDP is also patched to passthrough."
            ).format(ws_int)
            logging.warning(msg)
            print(msg, file=sys.stderr, flush=True)
            return None

        return real_init(
            backend=backend,
            init_method=init_method,
            timeout=timeout,
            world_size=world_size,
            rank=rank,
            store=store,
            group_name=group_name,
            pg_options=pg_options,
            device_id=device_id,
        )

    _patched._raidio_dist_patched = True  # type: ignore[attr-defined]
    dist_module.init_process_group = _patched
    _PATCHED = True
    msg = "[rAIdio dist-noop] patch applied to torch.distributed.init_process_group"
    logging.info(msg)
    print(msg, file=sys.stderr, flush=True)


class _DistLoaderProxy:
    """Wraps the real loader for torch.distributed; patches the module
    immediately after the real exec_module finishes."""

    def __init__(self, real_loader):
        self._real = real_loader

    def create_module(self, spec):
        if hasattr(self._real, "create_module"):
            return self._real.create_module(spec)
        return None

    def exec_module(self, module):
        self._real.exec_module(module)
        try:
            _patch_init_process_group(module)
        except Exception as e:
            logging.warning("[rAIdio dist-noop] post-import patch failed: %r", e)


class _DistFinder:
    """sys.meta_path finder that intercepts torch.distributed's spec
    and substitutes a wrapping loader."""

    def find_spec(self, fullname, path=None, target=None):
        if fullname != _TARGET:
            return None
        # Defer to the next finders in meta_path for the real spec.
        for finder in sys.meta_path:
            if finder is self:
                continue
            find = getattr(finder, "find_spec", None)
            if find is None:
                continue
            try:
                spec = find(fullname, path, target)
            except Exception:
                continue
            if spec is None or spec.loader is None:
                continue
            spec.loader = _DistLoaderProxy(spec.loader)
            return spec
        return None


def _patch_ddp_class(parallel_dist_module):
    """Replace DistributedDataParallel with a single-rank passthrough.
    train.py's downstream code already handles the unwrapped case via
    `hasattr(net, 'module')` checks (lines 228, 243, 596, 622), so an
    unwrapped model triggers the non-DDP code path naturally. No real
    DDP wrapping is needed for single-GPU training; gradient all-reduce
    over one rank is a mathematical no-op."""
    real_DDP = getattr(parallel_dist_module, "DistributedDataParallel", None)
    if real_DDP is None or getattr(real_DDP, "_raidio_passthrough", False):
        return

    class _PassthroughDDP(real_DDP):  # type: ignore[misc, valid-type]
        """Subclass of real DDP. For single-rank, __new__ returns the
        bare model directly (Python skips __init__ when __new__ returns
        a non-cls instance). For multi-rank, falls through to real DDP.
        Subclassing keeps `class X(DistributedDataParallel)` declarations
        like torch.nn.parallel.__init__.py:26 valid."""

        _raidio_passthrough = True

        def __new__(cls, module=None, *args, **kwargs):
            try:
                ws = int(os.environ.get("WORLD_SIZE", "1"))
            except (TypeError, ValueError):
                ws = 1
            if ws <= 1 and module is not None:
                msg = (
                    "[rAIdio dist-noop] DDP() wrap intercepted (world_size={}); "
                    "returning bare model"
                ).format(ws)
                logging.warning(msg)
                print(msg, file=sys.stderr, flush=True)
                return module
            return super().__new__(cls)

    parallel_dist_module.DistributedDataParallel = _PassthroughDDP
    msg = "[rAIdio dist-noop] patch applied to torch.nn.parallel.distributed.DistributedDataParallel"
    logging.info(msg)
    print(msg, file=sys.stderr, flush=True)


class _DDPLoaderProxy:
    """Wraps the real loader for torch.nn.parallel.distributed; patches
    the DDP class immediately after the real exec_module finishes."""

    def __init__(self, real_loader):
        self._real = real_loader

    def create_module(self, spec):
        if hasattr(self._real, "create_module"):
            return self._real.create_module(spec)
        return None

    def exec_module(self, module):
        self._real.exec_module(module)
        try:
            _patch_ddp_class(module)
        except Exception as e:
            logging.warning("[rAIdio dist-noop] post-import DDP patch failed: %r", e)


class _DDPFinder:
    """sys.meta_path finder that intercepts torch.nn.parallel.distributed's
    spec and substitutes a wrapping loader."""

    def find_spec(self, fullname, path=None, target=None):
        if fullname != "torch.nn.parallel.distributed":
            return None
        for finder in sys.meta_path:
            if finder is self:
                continue
            find = getattr(finder, "find_spec", None)
            if find is None:
                continue
            try:
                spec = find(fullname, path, target)
            except Exception:
                continue
            if spec is None or spec.loader is None:
                continue
            spec.loader = _DDPLoaderProxy(spec.loader)
            return spec
        return None


def _patch_mpl_tostring_rgb(mpl_agg_module):
    """Restore matplotlib.backends.backend_agg.FigureCanvasAgg.tostring_rgb,
    which was removed in matplotlib 3.8. ComfyUI-RVC's training-time
    spectrogram logging (rvc/infer/lib/train/utils.py:238) calls it via
        np.fromstring(fig.canvas.tostring_rgb(), dtype=np.uint8, sep="")
    Re-implementing it as a thin wrapper around buffer_rgba() keeps that
    code working without editing third-party RVC source."""
    cls = getattr(mpl_agg_module, "FigureCanvasAgg", None)
    if cls is None or hasattr(cls, "tostring_rgb"):
        return  # nothing to patch

    def tostring_rgb(self):
        import numpy as _np  # local import; numpy always available alongside matplotlib
        return _np.asarray(self.buffer_rgba())[..., :3].tobytes()

    cls.tostring_rgb = tostring_rgb
    msg = "[rAIdio mpl-shim] patched FigureCanvasAgg.tostring_rgb (matplotlib >= 3.8 removed it)"
    logging.info(msg)
    print(msg, file=sys.stderr, flush=True)


class _MplLoaderProxy:
    """Wraps the real loader for matplotlib.backends.backend_agg; patches
    FigureCanvasAgg.tostring_rgb after the real exec_module finishes."""

    def __init__(self, real_loader):
        self._real = real_loader

    def create_module(self, spec):
        if hasattr(self._real, "create_module"):
            return self._real.create_module(spec)
        return None

    def exec_module(self, module):
        self._real.exec_module(module)
        try:
            _patch_mpl_tostring_rgb(module)
        except Exception as e:
            logging.warning("[rAIdio mpl-shim] post-import patch failed: %r", e)


class _MplFinder:
    """sys.meta_path finder for matplotlib.backends.backend_agg."""

    def find_spec(self, fullname, path=None, target=None):
        if fullname != "matplotlib.backends.backend_agg":
            return None
        for finder in sys.meta_path:
            if finder is self:
                continue
            find = getattr(finder, "find_spec", None)
            if find is None:
                continue
            try:
                spec = find(fullname, path, target)
            except Exception:
                continue
            if spec is None or spec.loader is None:
                continue
            spec.loader = _MplLoaderProxy(spec.loader)
            return spec
        return None


def _install():
    # torch.distributed: patch directly if already loaded, else install finder.
    if _TARGET in sys.modules:
        try:
            _patch_init_process_group(sys.modules[_TARGET])
        except Exception as e:
            logging.warning("[rAIdio dist-noop] direct dist patch failed: %r", e)
    else:
        sys.meta_path.insert(0, _DistFinder())

    # torch.nn.parallel.distributed (DDP): same pattern.
    _DDP_TARGET = "torch.nn.parallel.distributed"
    if _DDP_TARGET in sys.modules:
        try:
            _patch_ddp_class(sys.modules[_DDP_TARGET])
        except Exception as e:
            logging.warning("[rAIdio dist-noop] direct DDP patch failed: %r", e)
    else:
        sys.meta_path.insert(0, _DDPFinder())

    # matplotlib.backends.backend_agg (RVC training-time spectrogram logging).
    _MPL_TARGET = "matplotlib.backends.backend_agg"
    if _MPL_TARGET in sys.modules:
        try:
            _patch_mpl_tostring_rgb(sys.modules[_MPL_TARGET])
        except Exception as e:
            logging.warning("[rAIdio mpl-shim] direct patch failed: %r", e)
    else:
        sys.meta_path.insert(0, _MplFinder())


def _pin_dist_to_loopback():
    """Select libuv-based gloo on Windows (PyTorch 2.4+) which uses
    libuv for socket operations. Don't set GLOO_SOCKET_IFNAME — its
    only valid Linux value 'lo' is invalid on Windows and forces gloo
    down the makeDeviceForInterface() path which then rejects it.
    With GLOO_USE_LIBUV=1 and IFNAME unset, libuv-gloo falls back to
    auto-detecting a usable local interface."""
    os.environ.setdefault("GLOO_USE_LIBUV", "1")
    os.environ.setdefault("MASTER_ADDR", "127.0.0.1")
    os.environ.setdefault("MASTER_PORT", "29500")


_install()
_pin_dist_to_loopback()
print("[rAIdio sitecustomize] dist no-op + loopback pinning applied", file=sys.stderr, flush=True)
